import{_ as t,c as i,o as s,a1 as e}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"DM 페어링 및 접근 제어: AI 어시스턴트 보호 | Clawdbot 튜토리얼","description":"Clawdbot의 DM 페어링 보호 메커니즘을 이해하고, CLI를 통해 모르는 발신자의 페어링 요청을 승인하고, 대기 중인 요청을 나열하며, 허용 목록을 관리하는 방법을 학습합니다. 본 튜토리얼은 페어링 프로세스, CLI 명령 사용, 접근 정책 구성 및 보안 모범 사례를 완전히 소개하며, 일반적인 오류 해결 및 doctor 명령을 포함합니다.","frontmatter":{"title":"DM 페어링 및 접근 제어: AI 어시스턴트 보호 | Clawdbot 튜토리얼","sidebarTitle":"모르는 발신자 접근 관리","subtitle":"DM 페어링 및 접근 제어: AI 어시스턴트 보호","description":"Clawdbot의 DM 페어링 보호 메커니즘을 이해하고, CLI를 통해 모르는 발신자의 페어링 요청을 승인하고, 대기 중인 요청을 나열하며, 허용 목록을 관리하는 방법을 학습합니다. 본 튜토리얼은 페어링 프로세스, CLI 명령 사용, 접근 정책 구성 및 보안 모범 사례를 완전히 소개하며, 일반적인 오류 해결 및 doctor 명령을 포함합니다.","tags":["입문","보안","페어링","접근 제어"],"prerequisite":["start-gateway-startup"],"order":50},"headers":[],"relativePath":"ko/moltbot/moltbot/start/pairing-approval/index.md","filePath":"ko/moltbot/moltbot/start/pairing-approval/index.md"}'),l={name:"ko/moltbot/moltbot/start/pairing-approval/index.md"};function o(n,a,r,d,p,c){return s(),i("div",null,[...a[0]||(a[0]=[e(`<h1 id="dm-페어링-및-접근-제어-ai-어시스턴트-보호" tabindex="-1">DM 페어링 및 접근 제어: AI 어시스턴트 보호 <a class="header-anchor" href="#dm-페어링-및-접근-제어-ai-어시스턴트-보호" aria-label="Permalink to &quot;DM 페어링 및 접근 제어: AI 어시스턴트 보호&quot;">​</a></h1><h2 id="학습-완료-후-할-수-있는-것" tabindex="-1">학습 완료 후 할 수 있는 것 <a class="header-anchor" href="#학습-완료-후-할-수-있는-것" aria-label="Permalink to &quot;학습 완료 후 할 수 있는 것&quot;">​</a></h2><p>본 튜토리얼을 완료한 후, 다음을 할 수 있게 됩니다:</p><ul><li>✅ 기본 DM 페어링 보호 메커니즘 이해</li><li>✅ 모르는 발신자의 페어링 요청 승인</li><li>✅ 대기 중인 페어링 요청 나열 및 관리</li><li>✅ 다른 DM 접근 정책 구성 (pairing/allowlist/open)</li><li>✅ doctor를 실행하여 보안 구성 검사</li></ul><h2 id="현재-문제-상황" tabindex="-1">현재 문제 상황 <a class="header-anchor" href="#현재-문제-상황" aria-label="Permalink to &quot;현재 문제 상황&quot;">​</a></h2><p>WhatsApp 또는 Telegram 채널을 구성했고 AI 어시스턴트와 대화하고 싶지만 다음 문제에 직면했을 수 있습니다:</p><ul><li>&quot;모르는 사람이 메시지를 보내는데 Clawdbot이 응답하지 않는 이유는 무엇인가요?&quot;</li><li>&quot;페어링 코드를 받았지만 의미를 모릅니다&quot;</li><li>&quot;특정 사람의 요청을 승인하고 싶지만 사용할 명령을 모릅니다&quot;</li><li>&quot;현재 승인 대기 중인 사람이 누구인지 어떻게 확인할 수 있나요?&quot;</li></ul><p>좋은 소식은: <strong>Clawdbot은 기본적으로 DM 페어링 보호가 활성화</strong>되어 있습니다. 이는 승인한 발신자만 AI 어시스턴트와 대화할 수 있도록 보장하기 위한 것입니다.</p><h2 id="언제-사용하는가" tabindex="-1">언제 사용하는가 <a class="header-anchor" href="#언제-사용하는가" aria-label="Permalink to &quot;언제 사용하는가&quot;">​</a></h2><p>다음이 필요할 때:</p><ul><li>🛡 <strong>개인 정보 보호</strong>: 신뢰할 수 있는 사람만 AI 어시스턴트와 대화할 수 있도록 보장</li><li>✅ <strong>모르는 사람 승인</strong>: 새로운 발신자가 AI 어시스턴트에 접근할 수 있도록 허용</li><li>🔒 <strong>엄격한 접근 제어</strong>: 특정 사용자의 접근 권한 제한</li><li>📋 <strong>일괄 관리</strong>: 모든 대기 중인 페어링 요청 보기 및 관리</li></ul><hr><h2 id="핵심-아이디어" tabindex="-1">핵심 아이디어 <a class="header-anchor" href="#핵심-아이디어" aria-label="Permalink to &quot;핵심 아이디어&quot;">​</a></h2><h3 id="dm-페어링이란" tabindex="-1">DM 페어링이란? <a class="header-anchor" href="#dm-페어링이란" aria-label="Permalink to &quot;DM 페어링이란?&quot;">​</a></h3><p>Clawdbot은 실제 메시징 플랫폼(WhatsApp, Telegram, Slack 등)에 연결됩니다. 이 플랫폼의 <strong>DM(직접 메시지)은 기본적으로 신뢰할 수 없는 입력으로 간주</strong>됩니다.</p><p>AI 어시스턴트를 보호하기 위해 Clawdbot은 <strong>페어링 메커니즘</strong>을 제공합니다:</p><div class="info custom-block"><p class="custom-block-title">페어링 프로세스</p><ol><li>모르는 발신자가 메시지를 보냅니다</li><li>Clawdbot이 해당 발신자가 승인되지 않았음을 감지합니다</li><li>Clawdbot이 <strong>페어링 코드</strong>(8자)를 반환합니다</li><li>발신자가 페어링 코드를 제공해야 합니다</li><li>CLI를 통해 코드를 승인합니다</li><li>발신자 ID가 허용 목록에 추가됩니다</li><li>발신자가 AI 어시스턴트와 정상적으로 대화할 수 있습니다</li></ol></div><h3 id="기본-dm-정책" tabindex="-1">기본 DM 정책 <a class="header-anchor" href="#기본-dm-정책" aria-label="Permalink to &quot;기본 DM 정책&quot;">​</a></h3><p><strong>모든 채널은 기본적으로 <code>dmPolicy=&quot;pairing&quot;</code>을 사용</strong>합니다. 이는 다음을 의미합니다:</p><table tabindex="0"><thead><tr><th>정책</th><th>동작</th></tr></thead><tbody><tr><td><code>pairing</code></td><td>알 수 없는 발신자가 페어링 코드를 받고 메시지가 처리되지 않음 (기본값)</td></tr><tr><td><code>allowlist</code></td><td><code>allowFrom</code> 목록의 발신자만 허용</td></tr><tr><td><code>open</code></td><td>모든 발신자 허용 (명시적으로 <code>&quot;*&quot;</code> 구성 필요)</td></tr><tr><td><code>disabled</code></td><td>DM 기능 완전히 비활성화</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">보안 경고</p><p>기본 <code>pairing</code> 모드가 가장 안전한 선택입니다. 특별한 요구 사항이 없는 한 <code>open</code> 모드로 수정하지 마십시오.</p></div><hr><h2 id="🎒-시작-전-준비" tabindex="-1">🎒 시작 전 준비 <a class="header-anchor" href="#🎒-시작-전-준비" aria-label="Permalink to &quot;🎒 시작 전 준비&quot;">​</a></h2><p>다음을 완료했는지 확인하십시오:</p><ul><li>[x] <a href="./../../getting-started/">빠른 시작</a> 튜토리얼 완료</li><li>[x] <a href="./../../gateway-startup/">Gateway 시작</a> 튜토리얼 완료</li><li>[x] 하나 이상의 메시징 채널 구성 (WhatsApp, Telegram, Slack 등)</li><li>[x] Gateway 실행 중</li></ul><hr><h2 id="따라해보세요" tabindex="-1">따라해보세요 <a class="header-anchor" href="#따라해보세요" aria-label="Permalink to &quot;따라해보세요&quot;">​</a></h2><h3 id="_1단계-페어링-코드의-출처-이해" tabindex="-1">1단계: 페어링 코드의 출처 이해 <a class="header-anchor" href="#_1단계-페어링-코드의-출처-이해" aria-label="Permalink to &quot;1단계: 페어링 코드의 출처 이해&quot;">​</a></h3><p>모르는 발신자가 Clawdbot에 메시지를 보낼 때 다음과 같은 응답을 받습니다:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Clawdbot: access not configured.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Telegram ID: 123456789</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Pairing code: AB3D7X9K</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ask the bot owner to approve with:</span></span>
<span class="line"><span>clawdbot pairing approve telegram &lt;code&gt;</span></span></code></pre></div><p><strong>페어링 코드의 핵심 특성</strong> (출처: <code>src/pairing/pairing-store.ts</code>):</p><ul><li><strong>8자</strong>: 입력 및 기억에 용이</li><li><strong>대문자와 숫자</strong>: 혼동 방지</li><li><strong>혼동 문자 제외</strong>: 0, O, 1, I 제외</li><li><strong>1시간 유효 기간</strong>: 시간 초과 시 자동 만료</li><li><strong>최대 3개의 대기 중인 요청 보관</strong>: 초과 시 가장 오래된 요청 자동 정리</li></ul><h3 id="_2단계-대기-중인-페어링-요청-나열" tabindex="-1">2단계: 대기 중인 페어링 요청 나열 <a class="header-anchor" href="#_2단계-대기-중인-페어링-요청-나열" aria-label="Permalink to &quot;2단계: 대기 중인 페어링 요청 나열&quot;">​</a></h3><p>터미널에서 다음 명령을 실행하십시오:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span></span></code></pre></div><p><strong>다음이 표시되어야 합니다</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pairing requests (1)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────────────────┬────────────────┬────────┬──────────────────────┐</span></span>
<span class="line"><span>│ Code            │ ID            │ Meta   │ Requested            │</span></span>
<span class="line"><span>├──────────────────┼────────────────┼────────┼──────────────────────┤</span></span>
<span class="line"><span>│ AB3D7X9K        │ 123456789      │        │ 2026-01-27T10:30:00Z │</span></span>
<span class="line"><span>└──────────────────┴────────────────┴────────┴──────────────────────┘</span></span></code></pre></div><p>대기 중인 요청이 없으면 다음이 표시됩니다:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No pending telegram pairing requests.</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">지원되는 채널</p><p>페어링 기능은 다음 채널을 지원합니다:</p><ul><li>telegram</li><li>whatsapp</li><li>slack</li><li>discord</li><li>signal</li><li>imessage</li><li>msteams</li><li>googlechat</li><li>bluebubbles</li></ul></div><h3 id="_3단계-페어링-요청-승인" tabindex="-1">3단계: 페어링 요청 승인 <a class="header-anchor" href="#_3단계-페어링-요청-승인" aria-label="Permalink to &quot;3단계: 페어링 요청 승인&quot;">​</a></h3><p>발신자가 제공한 페어링 코드를 사용하여 접근을 승인하십시오:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AB3D7X9K</span></span></code></pre></div><p><strong>다음이 표시되어야 합니다</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Approved telegram sender 123456789</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">승인 후 효과</p><p>승인 후 발신자 ID(123456789)가 해당 채널의 허용 목록에 자동으로 추가되며 다음 위치에 저장됩니다: <code>~/.clawdbot/credentials/telegram-allowFrom.json</code></p></div><h3 id="_4단계-발신자에게-알림-선택-사항" tabindex="-1">4단계: 발신자에게 알림 (선택 사항) <a class="header-anchor" href="#_4단계-발신자에게-알림-선택-사항" aria-label="Permalink to &quot;4단계: 발신자에게 알림 (선택 사항)&quot;">​</a></h3><p>발신자에게 자동으로 알리고 싶다면 <code>--notify</code> 플래그를 사용하십시오:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AB3D7X9K</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --notify</span></span></code></pre></div><p>발신자는 다음 메시지를 받습니다 (출처: <code>src/channels/plugins/pairing-message.ts</code>):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Clawdbot access approved. Send a message to start chatting.</span></span></code></pre></div><p><strong>참고</strong>: <code>--notify</code> 플래그는 Clawdbot Gateway가 실행 중이고 해당 채널이 활성 상태여야 합니다.</p><h3 id="_5단계-발신자가-정상적으로-대화할-수-있는지-확인" tabindex="-1">5단계: 발신자가 정상적으로 대화할 수 있는지 확인 <a class="header-anchor" href="#_5단계-발신자가-정상적으로-대화할-수-있는지-확인" aria-label="Permalink to &quot;5단계: 발신자가 정상적으로 대화할 수 있는지 확인&quot;">​</a></h3><p>발신자가 다시 메시지를 보내면 AI 어시스턴트가 정상적으로 응답해야 합니다.</p><hr><h2 id="체크포인트-✅" tabindex="-1">체크포인트 ✅ <a class="header-anchor" href="#체크포인트-✅" aria-label="Permalink to &quot;체크포인트 ✅&quot;">​</a></h2><p>다음 검사를 완료하여 구성이 올바른지 확인하십시오:</p><ul><li>[ ] <code>clawdbot pairing list &lt;channel&gt;</code>을 실행하여 대기 중인 요청을 볼 수 있음</li><li>[ ] <code>clawdbot pairing approve &lt;channel&gt; &lt;code&gt;</code>를 사용하여 성공적으로 승인할 수 있음</li><li>[ ] 승인된 발신자가 AI 어시스턴트와 정상적으로 대화할 수 있음</li><li>[ ] 페어링 코드가 1시간 후에 자동으로 만료됨 (다시 메시지를 보내어 확인 가능)</li></ul><hr><h2 id="일반적인-문제-해결" tabindex="-1">일반적인 문제 해결 <a class="header-anchor" href="#일반적인-문제-해결" aria-label="Permalink to &quot;일반적인 문제 해결&quot;">​</a></h2><h3 id="오류-1-페어링-코드를-찾을-수-없음" tabindex="-1">오류 1: 페어링 코드를 찾을 수 없음 <a class="header-anchor" href="#오류-1-페어링-코드를-찾을-수-없음" aria-label="Permalink to &quot;오류 1: 페어링 코드를 찾을 수 없음&quot;">​</a></h3><p><strong>오류 메시지</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No pending pairing request found for code: AB3D7X9K</span></span></code></pre></div><p><strong>가능한 원인</strong>:</p><ul><li>페어링 코드가 이미 만료됨 (1시간 초과)</li><li>페어링 코드 입력 오류 (대소문자 확인)</li><li>발신자가 실제로 메시지를 보내지 않음 (페어링 코드는 메시지 수신 시에만 생성됨)</li></ul><p><strong>해결 방법</strong>:</p><ul><li>발신자가 다시 메시지를 보내 새로운 페어링 코드를 생성하도록 요청</li><li>페어링 코드를 올바르게 복사했는지 확인 (대소문자 주의)</li></ul><h3 id="오류-2-채널이-페어링을-지원하지-않음" tabindex="-1">오류 2: 채널이 페어링을 지원하지 않음 <a class="header-anchor" href="#오류-2-채널이-페어링을-지원하지-않음" aria-label="Permalink to &quot;오류 2: 채널이 페어링을 지원하지 않음&quot;">​</a></h3><p><strong>오류 메시지</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Channel xxx does not support pairing</span></span></code></pre></div><p><strong>가능한 원인</strong>:</p><ul><li>채널 이름 철자 오류</li><li>해당 채널이 페어링 기능을 지원하지 않음</li></ul><p><strong>해결 방법</strong>:</p><ul><li><code>clawdbot pairing list</code>를 실행하여 지원되는 채널 목록 확인</li><li>올바른 채널 이름 사용</li></ul><h3 id="오류-3-알림-실패" tabindex="-1">오류 3: 알림 실패 <a class="header-anchor" href="#오류-3-알림-실패" aria-label="Permalink to &quot;오류 3: 알림 실패&quot;">​</a></h3><p><strong>오류 메시지</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Failed to notify requester: &lt;error details&gt;</span></span></code></pre></div><p><strong>가능한 원인</strong>:</p><ul><li>Gateway가 실행되지 않음</li><li>채널 연결 끊김</li><li>네트워크 문제</li></ul><p><strong>해결 방법</strong>:</p><ul><li>Gateway가 실행 중인지 확인</li><li>채널 연결 상태 확인: <code>clawdbot channels status</code></li><li><code>--notify</code> 플래그를 사용하지 않고 발신자에게 수동으로 알림</li></ul><hr><h2 id="요약" tabindex="-1">요약 <a class="header-anchor" href="#요약" aria-label="Permalink to &quot;요약&quot;">​</a></h2><p>본 튜토리얼은 Clawdbot의 DM 페어링 보호 메커니즘을 소개했습니다:</p><ul><li><strong>기본 보안</strong>: 모든 채널은 기본적으로 <code>pairing</code> 모드를 사용하여 AI 어시스턴트 보호</li><li><strong>페어링 프로세스</strong>: 모르는 발신자가 8자 페어링 코드를 받고 CLI를 통해 승인 필요</li><li><strong>관리 명령</strong>: <ul><li><code>clawdbot pairing list &lt;channel&gt;</code>: 대기 중인 요청 나열</li><li><code>clawdbot pairing approve &lt;channel&gt; &lt;code&gt;</code>: 페어링 승인</li></ul></li><li><strong>저장 위치</strong>: 허용 목록은 <code>~/.clawdbot/credentials/&lt;channel&gt;-allowFrom.json</code>에 저장</li><li><strong>자동 만료</strong>: 페어링 요청은 1시간 후 자동으로 만료</li></ul><p>기억하십시오: <strong>페어링 메커니즘은 Clawdbot의 보안 기반</strong>이며, 승인한 사람만 AI 어시스턴트와 대화할 수 있도록 보장합니다.</p><hr><h2 id="다음-튜토리얼-미리보기" tabindex="-1">다음 튜토리얼 미리보기 <a class="header-anchor" href="#다음-튜토리얼-미리보기" aria-label="Permalink to &quot;다음 튜토리얼 미리보기&quot;">​</a></h2><blockquote><p>다음 튜토리얼에서는 **<a href="./../../faq/troubleshooting/">문제 해결: 일반적인 문제 해결</a>**를 학습합니다.</p><p>다음을 배우게 됩니다:</p><ul><li>빠른 진단 및 시스템 상태 검사</li><li>Gateway 시작, 채널 연결, 인증 오류 등의 문제 해결</li><li>도구 호출 실패 및 성능 최적화 문제 해결 방법</li></ul></blockquote><hr><h2 id="부록-소스-코드-참조" tabindex="-1">부록: 소스 코드 참조 <a class="header-anchor" href="#부록-소스-코드-참조" aria-label="Permalink to &quot;부록: 소스 코드 참조&quot;">​</a></h2><details><summary><strong>클릭하여 소스 코드 위치 보기</strong></summary><blockquote><p>업데이트 시간: 2026-01-27</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>행 번호</th></tr></thead><tbody><tr><td>페어링 코드 생성 (8자, 혼동 문자 제외)</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L173-L181" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>173-181</td></tr><tr><td>페어링 요청 저장 및 TTL (1시간)</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L11-L14" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>11-14</td></tr><tr><td>페어링 승인 명령</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/cli/pairing-cli.ts#L107-L143" target="_blank" rel="noreferrer"><code>src/cli/pairing-cli.ts</code></a></td><td>107-143</td></tr><tr><td>페어링 코드 메시지 생성</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-messages.ts#L4-L20" target="_blank" rel="noreferrer"><code>src/pairing/pairing-messages.ts</code></a></td><td>4-20</td></tr><tr><td>허용 목록 저장</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L457-L461" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>457-461</td></tr><tr><td><code>pairing</code> 지원 채널 목록</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/channels/plugins/pairing.ts#L11-L16" target="_blank" rel="noreferrer"><code>src/channels/plugins/pairing.ts</code></a></td><td>11-16</td></tr><tr><td>기본 DM 정책 (pairing)</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/config/zod-schema.providers-core.ts#L93" target="_blank" rel="noreferrer"><code>src/config/zod-schema.providers-core.ts</code></a></td><td>93</td></tr></tbody></table><p><strong>핵심 상수</strong>:</p><ul><li><code>PAIRING_CODE_LENGTH = 8</code>: 페어링 코드 길이</li><li><code>PAIRING_CODE_ALPHABET = &quot;ABCDEFGHJKLMNPQRSTUVWXYZ23456789&quot;</code>: 페어링 코드 문자 집합 (0O1I 제외)</li><li><code>PAIRING_PENDING_TTL_MS = 60 * 60 * 1000</code>: 페어링 요청 유효 기간 (1시간)</li><li><code>PAIRING_PENDING_MAX = 3</code>: 최대 대기 중인 요청 수</li></ul><p><strong>핵심 함수</strong>:</p><ul><li><code>approveChannelPairingCode()</code>: 페어링 코드를 승인하고 허용 목록에 추가</li><li><code>listChannelPairingRequests()</code>: 대기 중인 페어링 요청 나열</li><li><code>upsertChannelPairingRequest()</code>: 페어링 요청 생성 또는 업데이트</li><li><code>addChannelAllowFromStoreEntry()</code>: 허용 목록에 발신자 추가</li></ul></details>`,92)])])}const b=t(l,[["render",o]]);export{g as __pageData,b as default};
